    focusMode: false,
    userName: 'Toto Wolff',
    unreadMessageCount: 6,
    activePath: '/',
    businessDetails: {
      linkedBusinesses: exampleBusinesses,
      selectedBusiness: exampleBusinesses[1],
      setSelectedBusiness: () => {}
    }
